/**
 * Prepare Input for SLOGAN ADAPTATION ENGINE v3.0
 * Transformation: Validated Products → LLM-ready Format (nur Struktur, keine Value-Änderungen)
 */

const input = $input.all();
if (input.length === 0) return [];

const firstItem = input[0].json;

// ===== PARSE INPUTS (unverändert aus Input holen) =====
const rawAnalyses = firstItem.analyses || [];
const nicheProfile = firstItem.NicheProfileSellingNiches;
const grund = firstItem.grund;
const originalSloganAnalysis = firstItem.OriginalSloganAnalysis;
const originalSlogan = firstItem.OriginalSlogan;

// ===== 1. NICHE CONTEXT (Werte 1:1 übernehmen) =====
const nicheContext = {
  name: nicheProfile.niche_name,
  signal_type: grund.signal_conversion.target_signal,
  dominant_patterns: nicheProfile.pattern_analysis
    .filter(p => p.present === true)
    .map(p => p.name),
  energy: grund.emotional_alignment.energy_level,
  tone: grund.emotional_alignment.tone_guidance,
  core_emotion: grund.emotional_alignment.core_emotion,
  top_insider_terms: nicheProfile.example_keywords || []
};

// ===== 2. REFERENCE PATTERNS (1:1 aus analyses) =====
const referencePatterns = rawAnalyses
  .filter(item => item.slogan && item.pattern)
  .slice(0, 5)
  .map(item => ({
    slogan: item.slogan,
    pattern: item.pattern,
    formula: item.formula,
    energy: item.energy,
    insider_terms: item.insider_terms || [],
    transfer_hint: item.transfer_hint || ""
  }));

// ===== 3. ORIGINAL CONTEXT (Werte 1:1) =====
const originalContext = {
  slogan: originalSlogan,
  pattern: originalSloganAnalysis.primary_pattern,
  signal: grund.signal_conversion.original_signal,
  element_count: grund.structural_insights.element_count,
  format_type: grund.structural_insights.format_type  // ← NUR Wert aus grund, KEINE Änderung
};

// ===== 4. CONVERSION CONTEXT (1:1) =====
const conversionRequired = {
  signal_shift: grund.signal_conversion.direction,
  reason: grund.signal_conversion.transformation_strategy
};

// ===== OUTPUT =====
return [{
  json: {
    niche_context: nicheContext,
    reference_patterns: referencePatterns,
    original: originalContext,
    conversion_required: conversionRequired
  }
}];

// Gewichtetes Scoring für Produkte basierend auf reviewsCount und rate
const items = $input.all();

// Scoring-Funktion: Kombiniert Reviews und Rating mit Wilson Score Confidence
function calculateScore(reviewsCount, rate) {
  // Normalisiere rate auf 0-1 Skala (von 0-5 auf 0-1)
  const normalizedRate = rate / 5;

  // Wilson Score Lower Bound für Konfidenz
  // Diese Formel bevorzugt Produkte mit mehr Reviews
  const n = reviewsCount;
  const p = normalizedRate;

  // Gewichtungsfaktoren
  const ratingWeight = 0.6;  // 40% Gewichtung für Rating
  const reviewWeight = 0.4;  // 60% Gewichtung für Review-Count

  // Logarithmische Skalierung der Review-Anzahl (verhindert, dass extrem hohe Zahlen dominieren)
  const reviewScore = Math.log(n + 1) / Math.log(100); // Normalisiert gegen ~100 Reviews

  // Kombinierter Score mit Confidence Boost
  const confidence = Math.sqrt(n) / (Math.sqrt(n) + 5); // Confidence steigt mit Review-Anzahl
  const finalScore = (ratingWeight * p + reviewWeight * reviewScore) * confidence;

  return finalScore;
}

// Berechne Score für jedes Item und speichere es
const scoredItems = items.map(item => {
  const reviewsCount = item.json.reviewsCount || 0;
  const rate = item.json.rate || 0;
  const score = calculateScore(reviewsCount, rate);

  return {
    ...item.json,
    _score: score  // Score hinzufügen
  };
});

// Sortiere nach Score (hoch zu niedrig)
scoredItems.sort((a, b) => b._score - a._score);

// Begrenze auf Top 20
const top20 = scoredItems.slice(0, 45);

// Gebe jedes Item einzeln aus (NICHT als Array)
return top20.map(item => ({
  json: item
}));

