/**
 * Prepare Input for SLOGAN ADAPTATION ENGINE v2.0
 * Transformation: Alle verfügbaren Daten einbeziehen
 * UPDATE: Top 10 Referenzen nach match_score sortiert
 */

const input = $input.all();
if (input.length === 0) return [];

const firstItem = input[0].json;

// ===== PARSE INPUTS =====
const rawAnalyses = firstItem.analyses || [];
const nicheProfile = firstItem.NicheProfileSellingNiches;
const grund = firstItem.grund;
const originalSloganAnalysis = firstItem.OriginalSloganAnalysis;
const originalSlogan = firstItem.OriginalSlogan;

// ===== 1. NICHE CONTEXT (VOLLSTÄNDIG) =====
const nicheContext = {
  name: nicheProfile.niche_name,

  // Signal & Patterns
  signal_type: grund.signal_conversion.target_signal,
  dominant_patterns: nicheProfile.pattern_analysis
    .filter(p => p.present === true)
    .map(p => p.name),

  // Energy & Emotion
  energy: grund.emotional_alignment.energy_level,
  tone: grund.emotional_alignment.tone_guidance,
  core_emotion: grund.emotional_alignment.core_emotion,
  emotional_keywords: grund.emotional_alignment.keywords,

  // Niche Details
  niche_summary: nicheProfile.niche_summary,
  sentiment: nicheProfile.sentiment,
  primary_emotions: nicheProfile.primary_emotions,
  emotional_archetype: nicheProfile.emotional_archetype,
  emotional_reality: nicheProfile.emotional_reality,

  // Insider Language
  top_insider_terms: nicheProfile.example_keywords || [],

  // Design Context (optional, aber hilfreich)
  design_concepts: nicheProfile.design_concepts,
  dominant_design_aesthetics: nicheProfile.dominant_design_aesthetics
};

// ===== 2. REFERENCE PATTERNS (TOP 10 NACH MATCH_SCORE SORTIERT) =====
const referencePatterns = rawAnalyses
  .filter(item => item.slogan && item.pattern && item.match_score !== undefined)
  .sort((a, b) => {
    const scoreA = parseFloat(a.match_score) || 0;
    const scoreB = parseFloat(b.match_score) || 0;
    return scoreB - scoreA; // Absteigend: höchster Score zuerst
  })
  .slice(0, 10) // ← EINZIGE ÄNDERUNG: Von 5 auf 10
  .map(item => ({
    slogan: item.slogan,
    pattern: item.pattern,
    formula: item.formula,
    energy: item.energy,
    insider_terms: item.insider_terms || [],
    transfer_hint: item.transfer_hint || "",
    match_score: item.match_score,
    image: item.image,
    url: item.url
  }));

// ===== 3. ORIGINAL CONTEXT (VOLLSTÄNDIG) =====
const originalContext = {
  slogan: originalSlogan,

  // Pattern Details
  pattern: originalSloganAnalysis.primary_pattern,
  sentence_structure: originalSloganAnalysis.sentence_structure,
  formula_pattern: originalSloganAnalysis.formula_pattern,

  // Power Words (wichtig für Punch Line!)
  power_words: originalSloganAnalysis.power_words,

  // Tone & Style
  wordplay_type: originalSloganAnalysis.wordplay_type,
  tone: originalSloganAnalysis.tone,
  specificity_level: originalSloganAnalysis.specificity_level,

  // Structure
  signal: grund.signal_conversion.original_signal,
  element_count: grund.structural_insights.element_count,
  format_type: grund.structural_insights.format_type
};

// ===== 4. CONVERSION CONTEXT (VOLLSTÄNDIG) =====
const conversionRequired = {
  signal_shift: grund.signal_conversion.direction,
  reason: grund.signal_conversion.transformation_strategy,

  // Structural Guidance
  punch_line_required: grund.structural_insights.punch_line_required,
  punch_line_strategy:grund.structural_insights.punch_line_strategy,

  // Justification (Kontext!)
  justification: grund.justification
};

// ===== OUTPUT =====
return [{
  json: {
    niche_context: nicheContext,
    reference_patterns: referencePatterns,
    original: originalContext,
    conversion_required: conversionRequired
  }
}];

